-- ═══════════════════════════════════════════════════════════════
-- V3 DISCRIMINATIVE PROBABILISTIC ENGINE — SCHEMA + SEED DATA
-- 25 diagnosis-selective composite states with anti-correlated mappings
-- ═══════════════════════════════════════════════════════════════

-- Table 1: Composite state definitions
CREATE TABLE v3_composite_states (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  state_name text UNIQUE NOT NULL,
  clinical_meaning text NOT NULL DEFAULT '',
  prior_probability numeric NOT NULL DEFAULT 0.1,
  conflict_group text,
  created_at timestamptz DEFAULT now()
);

-- Table 2: Feature → State mappings
CREATE TABLE v3_feature_state_mappings (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  state_id uuid REFERENCES v3_composite_states(id) ON DELETE CASCADE NOT NULL,
  feature_name text NOT NULL,
  log_likelihood_ratio numeric NOT NULL,
  created_at timestamptz DEFAULT now(),
  UNIQUE(state_id, feature_name)
);

-- Table 3: State → Diagnosis mappings (explicit positive AND negative)
CREATE TABLE v3_state_diagnosis_mappings (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  state_id uuid REFERENCES v3_composite_states(id) ON DELETE CASCADE NOT NULL,
  diagnosis_id uuid REFERENCES diagnoses(id) ON DELETE CASCADE NOT NULL,
  log_likelihood_ratio numeric NOT NULL,
  is_primary boolean DEFAULT false,
  created_at timestamptz DEFAULT now(),
  UNIQUE(state_id, diagnosis_id)
);

-- Indexes
CREATE INDEX idx_v3_fsm_state ON v3_feature_state_mappings(state_id);
CREATE INDEX idx_v3_fsm_feature ON v3_feature_state_mappings(feature_name);
CREATE INDEX idx_v3_sdm_state ON v3_state_diagnosis_mappings(state_id);
CREATE INDEX idx_v3_sdm_diagnosis ON v3_state_diagnosis_mappings(diagnosis_id);
CREATE INDEX idx_v3_cs_conflict ON v3_composite_states(conflict_group);

